/**
 * @param {number} n
 * @param {number} m
 * @param {number[][]} sources
 * @return {number[][]}
 */
function solve(n, m, sources) {
    // Initialize the grid with 0 (uncolored)
    const grid = Array(n).fill(0).map(() => Array(m).fill(0));

    // Initialize the priority queue for Multi-Source BFS.
    // The priority queue will store [distance, color, r, c].
    // Since we want to process nodes in increasing order of distance, and
    // for the same distance, the color comparison is implicitly handled by the BFS structure
    // (or we need a custom PQ if color affects tie-breaking, but here, the problem
    // states: if multiple colors arrive at the same time step (same distance), max color wins).
    // Standard BFS ensures we reach cells at increasing time steps (distance).
    // We'll use an array simulation for a min-heap based on distance.

    // A simple array acting as a queue for BFS.
    const queue = [];

    for (const [r, c, color] of sources) {
        // distance is 0 for initial sources
        queue.push({ dist: 0, color: color, r: r, c: c });
        grid[r][c] = color;
    }

    let head = 0;
    const directions = [[0, 1], [0, -1], [1, 0], [-1, 0]];

    // The BFS proceeds level by level, which corresponds to time steps.
    // We don't strictly need a priority queue if we process level by level, 
    // as all cells reached at the same distance are reached at the same time step.

    while (head < queue.length) {
        const current = queue[head++];
        const { dist, color, r, c } = current;

        for (const [dr, dc] of directions) {
            const nr = r + dr;
            const nc = c + dc;
            const nextDist = dist + 1;

            // Check boundaries
            if (nr >= 0 && nr < n && nc >= 0 && nc < m) {
                // Check if the cell is currently uncolored (grid[nr][nc] === 0)
                if (grid[nr][nc] === 0) {
                    // Tentatively color it with the current color and distance.
                    // We need a mechanism to track the *best* color/distance that reaches it.
                    // Since this is a standard BFS where distance increases monotonically, 
                    // the *first* time we reach an uncolored cell, it's at the minimum time.

                    // However, the rule is: "If multiple colors arrive at the same time step, 
                    // the cell adopts the maximum value color."

                    // A standard BFS guarantees that the first arrival is the fastest.
                    // If multiple sources reach (nr, nc) at the *same* time T, 
                    // they will all be in the queue at distance T.

                    // To handle the max color rule correctly for simultaneous arrivals, 
                    // we need to check if the current color is better than what's already recorded 
                    // for that cell, but only if the time is the same.

                    // Since we are only adding to the queue if grid[nr][nc] === 0, 
                    // the first cell to be colored at time T by ANY source determines the color if we don't check for simultaneous arrivals.

                    // Let's use a separate tracking mechanism or refine the BFS state.
                    // Let's store [min_dist, max_color] for each cell.
                }
            }
        }
    }

    // Re-implementing using Dijkstra-like structure focusing on distance, 
    // but allowing re-visiting if a better color arrives at the same time.

    // state[r][c] = {dist: number, color: number}
    const state = Array(n).fill(0).map(() => Array(m).fill(null));

    // Priority Queue stores [distance, -color, r, c]
    // We negate color because we want a MIN-heap on distance, and for ties, 
    // a MAX-heap on color (i.e., smallest negative color).
    // JS doesn't have a native PQ, so we simulate a simple one or rely on careful queue management.

    // For simplicity and correctness in a contest setting, we use an array as a queue/list
    // and process it iteratively, simulating the priority order.

    // Let's use a structure that holds all potential "arrival events" sorted by time, then color.
    // Event: [time, -color, r, c]
    const pq = [];

    for (const [r, c, color] of sources) {
        // Initial state: time 0, color, r, c
        pq.push([0, -color, r, c]);
        state[r][c] = { dist: 0, color: color };
    }

    // Simple bubble sort approach for PQ simulation (since N*M is small enough <= 10^5)
    // A proper heap implementation would be faster, but let's stick to the structure.
    // Sorting the whole list in every step is O(E log E), too slow. We must use a Heap structure.

    // Using a minimal Heap implementation for the simulation:
    class MinPriorityQueue {
        constructor() {
            // Stores [distance, negative_color, r, c]
            this.heap = [];
        }

        isEmpty() {
            return this.heap.length === 0;
        }

        _compare(i, j) {
            // Compare based on distance (primary key, ascending)
            if (this.heap[i][0] !== this.heap[j][0]) {
                return this.heap[i][0] - this.heap[j][0];
            }
            // Compare based on negative color (secondary key, ascending, meaning actual color descending)
            return this.heap[i][1] - this.heap[j][1];
        }

        _swap(i, j) {
            [this.heap[i], this.heap[j]] = [this.heap[j], this.heap[i]];
        }

        _heapifyUp(index) {
            while (index > 0) {
                let parentIndex = Math.floor((index - 1) / 2);
                if (this._compare(index, parentIndex) < 0) {
                    this._swap(index, parentIndex);
                    index = parentIndex;
                } else {
                    break;
                }
            }
        }

        _heapifyDown(index) {
            let smallest = index;
            const left = 2 * index + 1;
            const right = 2 * index + 2;

            if (left < this.heap.length && this._compare(left, smallest) < 0) {
                smallest = left;
            }
            if (right < this.heap.length && this._compare(right, smallest) < 0) {
                smallest = right;
            }

            if (smallest !== index) {
                this._swap(index, smallest);
                this._heapifyDown(smallest);
            }
        }

        push(item) {
            this.heap.push(item);
            this._heapifyUp(this.heap.length - 1);
        }

        pop() {
            if (this.isEmpty()) return null;
            if (this.heap.length === 1) return this.heap.pop();

            const root = this.heap[0];
            this.heap[0] = this.heap.pop();
            this._heapifyDown(0);
            return root;
        }
    }

    const pq_heap = new MinPriorityQueue();

    // Re-initialize PQ and state with sources
    for (const [r, c, color] of sources) {
        pq_heap.push([0, -color, r, c]);
        state[r][c] = { dist: 0, color: color };
    }

    const finalGrid = Array(n).fill(0).map(() => Array(m).fill(0));

    while (!pq_heap.isEmpty()) {
        const [d, negC, r, c] = pq_heap.pop();
        const color = -negC;

        // Check for outdated entry (stale in PQ)
        // If the current recorded state for (r, c) is better (lower distance, or same distance but higher color)
        // than the entry we popped, skip it.
        if (state[r][c] && (d > state[r][c].dist || (d === state[r][c].dist && color < state[r][c].color))) {
            continue;
        }

        // Update final grid representation
        finalGrid[r][c] = color;

        for (const [dr, dc] of directions) {
            const nr = r + dr;
            const nc = c + dc;
            const nextDist = d + 1;

            if (nr >= 0 && nr < n && nc >= 0 && nc < m) {
                const existingState = state[nr][nc];

                // If unvisited OR if the new arrival is strictly better
                if (!existingState) {
                    // New arrival
                    state[nr][nc] = { dist: nextDist, color: color };
                    pq_heap.push([nextDist, -color, nr, nc]);
                } else {
                    // Already visited/queued. Compare arrival time/color.

                    // Case 1: Faster arrival
                    if (nextDist < existingState.dist) {
                        state[nr][nc] = { dist: nextDist, color: color };
                        pq_heap.push([nextDist, -color, nr, nc]);
                    } 
                    // Case 2: Same time arrival (d + 1 == existingState.dist)
                    else if (nextDist === existingState.dist) {
                        // Max color wins
                        if (color > existingState.color) {
                            // This is an improvement in color at the same time step
                            state[nr][nc] = { dist: nextDist, color: color };
                            // Push the updated, better state into the queue to propagate this max color
                            pq_heap.push([nextDist, -color, nr, nc]);
                        }
                    } 
                    // Case 3: Slower arrival (nextDist > existingState.dist) -> Ignore
                }
            }
        }
    }

    return finalGrid;
}

