package main

// A structure to hold the state of a cell: minimum distance and the color that achieved it.
type CellState struct {
	Dist  int64
	Color int64
}

// An item in the priority queue. We use a custom struct to manage the priority.
// Priority: (Distance ASC, Color DESC)
type PQItem struct {
	Dist  int64
	Color int64
	R     int64
	C     int64
}

// MinPriorityQueue implements a min-heap based on the required priority rules.
type MinPriorityQueue struct {
	items []PQItem
}

func NewMinPriorityQueue() *MinPriorityQueue {
	return &MinPriorityQueue{items: make([]PQItem, 0)}
}

func (pq *MinPriorityQueue) isEmpty() bool {
	return len(pq.items) == 0
}

func (pq *MinPriorityQueue) swap(i, j int) {
	pq.items[i], pq.items[j] = pq.items[j], pq.items[i]
}

// compare returns true if item i has higher priority (should come before) item j.
// Higher priority means smaller distance, or if distances are equal, larger color.
func (pq *MinPriorityQueue) compare(i, j int) bool {
	if pq.items[i].Dist != pq.items[j].Dist {
		return pq.items[i].Dist < pq.items[j].Dist // Smaller distance is higher priority
	}
	return pq.items[i].Color > pq.items[j].Color // Larger color is higher priority if distances are equal
}

func (pq *MinPriorityQueue) heapifyUp(index int) {
	for index > 0 {
		parentIndex := (index - 1) / 2
		if pq.compare(index, parentIndex) {
			pq.swap(index, parentIndex)
			index = parentIndex
		} else {
			break
		}
	}
}

func (pq *MinPriorityQueue) heapifyDown(index int) {
	n := len(pq.items)
	for {
		leftChild := 2*index + 1
		rightChild := 2*index + 2
		highestPriority := index

		// Check left child
		if leftChild < n && pq.compare(leftChild, highestPriority) {
			highestPriority = leftChild
		}

		// Check right child
		if rightChild < n && pq.compare(rightChild, highestPriority) {
			highestPriority = rightChild
		}

		if highestPriority != index {
			pq.swap(index, highestPriority)
			index = highestPriority
		} else {
			break
		}
	}
}

func (pq *MinPriorityQueue) Push(item PQItem) {
	pq.items = append(pq.items, item)
	pq.heapifyUp(len(pq.items) - 1)
}

func (pq *MinPriorityQueue) Pop() (PQItem, bool) {
	if pq.isEmpty() {
		return PQItem{}, false
	}
	n := len(pq.items) - 1
	pq.swap(0, n)
	item := pq.items[n]
	pq.items = pq.items[:n]
	pq.heapifyDown(0)
	return item, true
}

func solve(n int64, m int64, sources [][]int64) [][]int64 {
	// state[r][c] stores the best known state to reach (r, c)
	state := make([][]CellState, n)
	for i := int64(0); i < n; i++ {
		state[i] = make([]CellState, m)
		for j := int64(0); j < m; j++ {
			state[i][j] = CellState{Dist: -1, Color: 0} // -1 indicates unvisited/infinity
		}
	}

	pq := NewMinPriorityQueue()

	// Initialize sources
	for _, source := range sources {
		r, c, color := source[0], source[1], source[2]

		// Initial state: distance 0, color
		state[r][c] = CellState{Dist: 0, Color: color}
		pq.Push(PQItem{Dist: 0, Color: color, R: r, C: c})
	}

	finalGrid := make([][]int64, n)
	for i := int64(0); i < n; i++ {
		finalGrid[i] = make([]int64, m)
	}

	directions := []struct{ dr, dc int64 }{{0, 1}, {0, -1}, {1, 0}, {-1, 0}}

	for !pq.isEmpty() {
		item, _ := pq.Pop()
		d, color, r, c := item.Dist, item.Color, item.R, item.C

		// Stale check: If we found a strictly better path already, ignore this older entry.
		// A path is better if it arrives faster, OR if it arrives at the same time 
		// but has a strictly larger color (due to the PQ ordering, this might be slightly complex, 
		// but checking against the current state is robust).
		currentState := state[r][c]
		if currentState.Dist != -1 && (d > currentState.Dist || (d == currentState.Dist && color < currentState.Color)) {
			continue
		}

		// Update the final result grid
		finalGrid[r][c] = color

		// Explore neighbors
		for _, dir := range directions {
			nr, nc := r+dir.dr, c+dir.dc

			if nr >= 0 && nr < n && nc >= 0 && nc < m {
				nextDist := d + 1
				existingState := state[nr][nc]

				if existingState.Dist == -1 {
					// Case 1: Unvisited cell
					state[nr][nc] = CellState{Dist: nextDist, Color: color}
					pq.Push(PQItem{Dist: nextDist, Color: color, R: nr, C: nc})
				} else {
					// Case 2: Cell already visited/in queue. Compare arrival.

					// Faster arrival: Always update and push
					if nextDist < existingState.Dist {
						state[nr][nc] = CellState{Dist: nextDist, Color: color}
						pq.Push(PQItem{Dist: nextDist, Color: color, R: nr, C: nc})
					} else if nextDist == existingState.Dist {
						// Same time arrival: Max color wins
						if color > existingState.Color {
							// Improvement found at the same time step
							state[nr][nc] = CellState{Dist: nextDist, Color: color}
							// Must push the improved state to propagate the better color outwards
							pq.Push(PQItem{Dist: nextDist, Color: color, R: nr, C: nc})
						}
					}
					// If nextDist > existingState.Dist, ignore (slower arrival)
				}
			}
		}
	}

	return finalGrid
}
