	Dist  int64
	NegColor int64 // Negative of color to simulate max-heap on color during distance ties
	R     int64
	C     int64
}

// MinPriorityQueue implementation (using a slice-based heap)
type MinPriorityQueue struct {
	heap []PQItem
}

func NewMinPriorityQueue() *MinPriorityQueue {
	return &MinPriorityQueue{heap: make([]PQItem, 0)}
}

func (pq *MinPriorityQueue) IsEmpty() bool {
	return len(pq.heap) == 0
}

func (pq *MinPriorityQueue) size() int {
	return len(pq.heap)
}

// Comparison logic:
// 1. Primary: Smallest Distance (Ascending)
// 2. Secondary: Smallest NegColor (Ascending) -> Largest Actual Color (Descending)
func (pq *MinPriorityQueue) compare(i, j int) bool {
	if pq.heap[i].Dist != pq.heap[j].Dist {
		return pq.heap[i].Dist < pq.heap[j].Dist // Smaller distance comes first
	}
	// If distances are equal, smaller NegColor comes first (i.e., larger actual color)
	return pq.heap[i].NegColor < pq.heap[j].NegColor
}

func (pq *MinPriorityQueue) swap(i, j int) {
	pq.heap[i], pq.heap[j] = pq.heap[j], pq.heap[i]
}

func (pq *MinPriorityQueue) heapifyUp(index int) {
	for index > 0 {
		parentIndex := (index - 1) / 2
		if pq.compare(index, parentIndex) < 0 {
			pq.swap(index, parentIndex)
			index = parentIndex
		} else {
			break
		}
	}
}

func (pq *MinPriorityQueue) heapifyDown(index int) {
	n := pq.size()
	for {
		smallest := index
		left := 2*index + 1
		right := 2*index + 2

		if left < n && pq.compare(left, smallest) < 0 {
			smallest = left
		}
		if right < n && pq.compare(right, smallest) < 0 {
			smallest = right
		}

		if smallest != index {
			pq.swap(index, smallest)
			index = smallest
		} else {
			break
		}
	}
}

func (pq *MinPriorityQueue) Push(item PQItem) {
	pq.heap = append(pq.heap, item)
	pq.heapifyUp(pq.size() - 1)
}

