	if pq.IsEmpty() {
		// Should not happen if called correctly
		return PQItem{} 
	}
	n := pq.size()
	pq.swap(0, n-1)
	item := pq.heap[n-1]
	pq.heap = pq.heap[:n-1]
	pq.heapifyDown(0)
	return item
