func NewMinPriorityQueue() *MinPriorityQueue {
	return &MinPriorityQueue{
		heap: make([][]int64, 0),
	}
}

func (pq *MinPriorityQueue) isEmpty() bool {
	return len(pq.heap) == 0
}

// Compares two elements. Returns true if i has higher priority (comes before j).
// Priority: Min distance first. If equal, Max color first (Min negative color).
func (pq *MinPriorityQueue) compare(i, j int) bool {
	// Compare distance (heap[i][0] vs heap[j][0])
	if pq.heap[i][0] != pq.heap[j][0] {
		return pq.heap[i][0] < pq.heap[j][0]
	}
	// Compare negative color (heap[i][1] vs heap[j][1]). Smaller negative value means larger color.
	return pq.heap[i][1] < pq.heap[j][1]
}

func (pq *MinPriorityQueue) swap(i, j int) {
	pq.heap[i], pq.heap[j] = pq.heap[j], pq.heap[i]
}

func (pq *MinPriorityQueue) heapifyUp(index int) {
	for index > 0 {
		parentIndex := (index - 1) / 2
		if pq.compare(index, parentIndex) {
			pq.swap(index, parentIndex)
			index = parentIndex
		} else {
			break
		}
	}
}

func (pq *MinPriorityQueue) heapifyDown(index int) {
	n := len(pq.heap)
	for {
		smallest := index
		left := 2*index + 1
		right := 2*index + 2

		if left < n && pq.compare(left, smallest) {
			smallest = left
		}
		if right < n && pq.compare(right, smallest) {
			smallest = right
		}

		if smallest != index {
			pq.swap(index, smallest)
			index = smallest
		} else {
			break
		}
	}
}

func (pq *MinPriorityQueue) Push(item []int64) {
	pq.heap = append(pq.heap, item)
	pq.heapifyUp(len(pq.heap) - 1)
}

func (pq *MinPriorityQueue) Pop() []int64 {
	if pq.isEmpty() {
		return nil
	}
	n := len(pq.heap)
	if n == 1 {
		return pq.heap[0]
	}

	root := pq.heap[0]
	pq.heap[0] = pq.heap[n-1]
	pq.heap = pq.heap[:n-1]
	pq.heapifyDown(0)
	return root
}

